@spec arrange_view_spec  src=tests/specs/arrange_view_spec.lua  loc=508  sha=1278d64  cases=29
@exercises configManager (h.cm), arrangeView (av), commandManager (h.cmgr), arrangeManager (am2)
@surface   cm:set, av:cursorRow, av:cursorCol, av:setCursor, av:setGridSize, av:scroll, av:scrollBy, av:setMaxCol, av:beatPerRow, av:setBeatPerRow, cm:get, av:rowToQN, av:paletteSlot, av:setPaletteSlot, av:focus, av:setFocus, cmgr:push, cmgr:invoke, am2:tracksTakes, av:tracksTakes, av:lassoCandidate, av:selectionSet, av:toggleSelected, av:isSelected, av:dragCandidate, av:commitDrag, av:qnToRow
@harness   mk, reaper:setTrackName, reaper:addItem, reaper:setProjectTracks

# Intent
  arrangeView: in-memory cursor/scroll + persisted beatPerRow, mirroring
  the trackerView/editCursor split (cursor is transient, density persists).

# Helpers
  @fn mkAv(harness)  @ 7-13
  @fn mkArrange(harness, items)  @ 17-36
      -- Build an av over a fake project. items: list of {track, name, pos, len?}.
      -- Tracks are created in first-seen order; beatPerRow is 1 (1 row = 1 QN).
  @fn takeAt(list, startQN)  @ 38-40

# Cases
  @case 'cursor defaults to (0,0); setCursor clamps negatives and floors'  [harness]  @ 44-52
  @case 'scroll defaults to (0,0); setGridSize alone does not move scroll'  [harness]  @ 56-62
  @case 'cursor moving below the visible band scrolls down to follow'  [harness]  @ 66-73
  @case 'cursor moving above the visible band scrolls up to follow'  [harness]  @ 77-85
  @case 'horizontal follow tracks cursorCol against gridCols'  [harness]  @ 89-99
  @case 'setGridSize shrinking the viewport re-follows the cursor in place'  [harness]  @ 103-114
  @case 'scrollBy pans the viewport without moving the cursor'  [harness]  @ 118-127
  @case 'scrollBy clamps to >= 0 and cursor-nav re-follows the cursor'  [harness]  @ 131-142
  @case 'scroll-right stops once the last column is fully visible'  [harness]  @ 146-154
  @case 'a same-dims setGridSize after a wheel-scroll leaves scroll alone'  [harness]  @ 158-166
  @case 'beatPerRow defaults to cm value; setter clamps minimum'  [harness]  @ 170-179
  @case 'setBeatPerRow holds the cursor QN (zoom anchors on cursor) and clamps max'  [harness]  @ 183-195
  @case 'paletteSlot defaults nil; setter clamps to 0..61; nil clears'  [harness]  @ 199-213
  @case 'focus defaults nil; setFocus stores an opaque handle, nil clears'  [harness]  @ 217-226
  @case 'no selection + on-screen cursor: edit acts on the cursor take, leaves it unselected'  [harness]  @ 230-246
  @case 'no selection + off-screen cursor: an edit is a no-op'  [harness]  @ 250-266
  @case 'a held selection wins over the cursor take'  [harness]  @ 270-289
  @case 'lasso selects every take whose span intersects the swept rect'  [harness]  @ 293-309
  @case 'a multi-selection deletes every selected take in one pass'  [harness]  @ 313-327
  @case 'nudge refuses entirely when any selected take is blocked'  [harness]  @ 331-348
  @case 'nudge slides a contiguous selected block without self-collision'  [harness]  @ 352-367
  @case 'a single-target command no-ops on a multi-selection'  [harness]  @ 371-384
  @case 'arrangeClearSelection empties the selection'  [harness]  @ 388-399
  @case 'addToSelection unions handles without duplicating a present one'  [harness]  @ 403-417
  @case 'toggleSelected adds an absent handle and removes a present one'  [harness]  @ 421-434
  @case 'group drag slides the whole selection by one delta'  [harness]  @ 438-454
  @case 'group drag refuses when a member would hit an outside take'  [harness]  @ 458-471
  @case 'group drag with Alt duplicates the block and reselects the copies'  [harness]  @ 475-493
  @case 'qnToRow / rowToQN are inverses through beatPerRow'  [harness]  @ 497-506

